Below is a **complete, self‑contained binding** that lets OCaml code walk a libpcapng file and run an OCaml callback on every frame.  
The binding is split into two parts:

* **`pcapng.mli`** – the public OCaml interface that users will `open Pcapng`.
* **`pcapng_stubs.cpp`** – the C/​C++ stub that talks to the C++ libpcapng library and marshals data to/from OCaml.

Everything you need to compile the binding is included in the two files; you only have to add the libpcapng headers/link‑flags that match your installation.

---

## 1.  `pcapng.mli` – public OCaml interface

```ocaml
(*--------------------------------------------------------------------
   libpcapng OCaml binding – high‑level interface
  --------------------------------------------------------------------*)

(** An opaque handle to an opened pcapng file. *)
type t

(** A single network frame as seen by libpcapng. *)
type frame = {
  ts   : float;          (** timestamp (seconds since epoch, double) *)
  len  : int;            (** captured length of the frame *)
  data : bytes;          (** raw packet bytes *)
}

(** Open a pcapng file for reading.  Raises [Failure] if the file cannot
    be opened or the format is invalid. *)
val open_file : string -> t

(** Walk the whole file and call the supplied function for each frame.
    The callback may raise; the exception is propagated to the caller and
    iteration stops immediately. *)
val iter_frames : t -> (frame -> unit) -> unit

(** Close the file and free all resources.  After a call to [close] the
    handle must not be used again. *)
val close : t -> unit
```

*Notes on the interface*

* The `frame` type is a plain OCaml record – easy to pattern‑match on.
* The iterator is **push‑style** (`iter_frames handle f`) because it lets the
  C++ code drive the loop and call back into OCaml, which is the natural way
  to expose a C++ iterator.
* The handle `t` is a custom block with a finaliser, so resources are also
  reclaimed automatically by the GC if the user forgets to call `close`.

---

## 2.  `pcapng_stubs.cpp` – C/​C++ glue

```cpp
/*--------------------------------------------------------------------
   libpcapng OCaml binding – C++ stubs
   Compile with:  ocamlc -c -ccopt -std=c++11 pcapng_stubs.cpp
   Link with:     -lpcapng (or whatever the library name is)
  --------------------------------------------------------------------*/

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>

#include <pcapng/reader.hpp>          // <-- libpcapng C++ header
#include <cstring>                    // memcpy
#include <exception>

/* ------------------------------------------------------------------ */
/*  OCaml custom block that holds the C++ reader object                */
/* ------------------------------------------------------------------ */

struct pcapng_handle {
  pcapng::Reader *reader;   // owned pointer
};

/* finaliser – called when the OCaml value is GC‑collected */
static void pcapng_finalize(value v) {
  pcapng_handle *h = (pcapng_handle *)Data_custom_val(v);
  if (h->reader) {
    delete h->reader;
    h->reader = nullptr;
  }
}

/* custom operations table (only finaliser is needed for now) */
static struct custom_operations pcapng_custom_ops = {
  "pcapng.handle",               // identifier (must be unique)
  pcapng_finalize,
  custom_compare_default,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  custom_compare_ext_default,
  custom_fixed_length_default
};

/* ------------------------------------------------------------------ */
/*  Helper to allocate a fresh custom block holding a new Reader       */
/* ------------------------------------------------------------------ */

static value alloc_handle(pcapng::Reader *r) {
  value v = caml_alloc_custom(&pcapng_custom_ops,
                              sizeof(pcapng_handle),
                              /*memory*/0,
                              /*max*/ 0);
  pcapng_handle *h = (pcapng_handle *)Data_custom_val(v);
  h->reader = r;
  return v;
}

/* ------------------------------------------------------------------ */
/*  OCaml entry points                                                */
/* ------------------------------------------------------------------ */

/*  val open_file : string -> t  */
extern "C" CAMLprim value caml_pcapng_open_file(value v_path) {
  CAMLparam1(v_path);
  const char *c_path = String_val(v_path);
  pcapng::Reader *r = nullptr;
  try {
    r = new pcapng::Reader(c_path);
  } catch (const std::exception &e) {
    caml_failwith(e.what());
  }
  CAMLreturn(alloc_handle(r));
}

/*  val close : t -> unit  */
extern "C" CAMLprim value caml_pcapng_close(value v_handle) {
  CAMLparam1(v_handle);
  pcapng_handle *h = (pcapng_handle *)Data_custom_val(v_handle);
  if (h->reader) {
    delete h->reader;
    h->reader = nullptr;
  }
  CAMLreturn(Val_unit);
}

/*  val iter_frames : t -> (frame -> unit) -> unit  */
extern "C" CAMLprim value caml_pcapng_iter_frames(value v_handle,
                                                 value v_fun) {
  CAMLparam2(v_handle, v_fun);
  pcapng_handle *h = (pcapng_handle *)Data_custom_val(v_handle);
  if (!h->reader) caml_failwith("Pcapng handle is closed");

  try {
    for (auto it = h->reader->begin(); it != h->reader->end(); ++it) {
      const pcapng::Frame &f = *it;

      /* Build the OCaml [frame] record */
      CAMLlocal3(v_frame, v_ts, v_data);
      v_frame = caml_alloc(3, 0);               // 3 fields, tag 0 (record)

      /* timestamp – double */
      v_ts = caml_copy_double(f.timestamp);
      Store_field(v_frame, 0, v_ts);

      /* length – int */
      Store_field(v_frame, 1, Val_int(f.length));

      /* data – bytes */
      v_data = caml_alloc_string(f.data.size());
      if (f.data.size() > 0)
        std::memcpy(String_val(v_data), f.data.data(), f.data.size());
      Store_field(v_frame, 2, v_data);

      /* Call the user supplied OCaml function.
         If it raises, the exception propagates out of this loop. */
      caml_callback(v_fun, v_frame);
    }
  } catch (const std::exception &e) {
    caml_failwith(e.what());
  }
  CAMLreturn(Val_unit);
}

/* --------------------------------------------------------------------
   End of pcapng_stubs.cpp
   -------------------------------------------------------------------- */
```

### How it works

* **`pcapng_handle`** – a tiny C++ struct stored inside an OCaml custom block.
  The block’s finaliser (`pcapng_finalize`) deletes the `pcapng::Reader*`
  automatically, so the resource is reclaimed even if the user forgets to call
  `close`.

* **`open_file`** – constructs a `pcapng::Reader` (the libpcapng entry point)
  and wraps it in a custom block.

* **`iter_frames`** – walks the iterator provided by `pcapng::Reader`.  
  For each native `pcapng::Frame` we allocate an OCaml record:

  ```ocaml
  { ts = <float>; len = <int>; data = <bytes> }
  ```

  The record is built with `caml_alloc(3,0)` (three fields, record tag 0).  
  The raw packet bytes are copied into an OCaml `bytes` value (`caml_alloc_string`).

  The callback is invoked with `caml_callback`.  
  If the OCaml function raises, the exception automatically propagates out of
  the C++ loop; the stub simply aborts iteration and returns the exception to
  the caller.

* **`close`** – explicit resource release; after it the handle is unusable.

### Building the binding

Assuming the libpcapng headers are reachable as `#include <pcapng/reader.hpp>` and
the library links with `-lpcapng`:

```sh
# Compile the stub (needs a C++ compiler, e.g. g++)
ocamlc -c -ccopt -std=c++11 pcapng_stubs.cpp

# Compile the (optional) .ml that just opens the .mli
ocamlc -c pcapng.ml   # empty file that just does "include Pcapng"

# Build a test program
ocamlc -custom -o test \
  pcapng.cmo pcapng_stubs.o \
  -cclib -lpcapng
```

You can now write OCaml code such as:

```ocaml
(* test.ml *)
let () =
  let p = Pcapng.open_file "sample.pcapng" in
  Pcapng.iter_frames p (fun frm ->
      Printf.printf "frame %d bytes @ %.6f\n%!"
        frm.Pcapng.len frm.Pcapng.ts);
  Pcapng.close p
```

Compile and run `test`; each frame in the file will be printed, demonstrating
the callback mechanism.

---

### Summary

* **`pcapng.mli`** – clean, idiomatic OCaml API (`open_file`, `iter_frames`,
  `close`, plus a `frame` record).
* **`pcapng_stubs.cpp`** – minimal C++ stub that:
  * stores the C++ `Reader` in a custom block,
  * builds an OCaml `frame` record on the fly,
  * calls back into OCaml for each frame,
  * propagates exceptions and cleans up resources automatically.

Feel free to extend the interface (e.g. expose more fields, add a `next`‑style
iterator, or support writing) – the skeleton above shows the essential pattern
for any C++ iterator that needs to invoke OCaml callbacks.
